# Shapes module - implements interfaces from types module
from types import IShape, IDrawable, Color, Point

@abstract
class ShapeBase(IShape):
    name: str
    color: Color

    def __init__(self, name: str, color: Color):
        self.name = name
        self.color = color

    @virtual
    def describe(self) -> str:
        return f"{self.name} with color {self.color}"

    def get_color(self) -> Color:
        return self.color

class Rectangle(ShapeBase, IDrawable):
    width: float
    height: float
    top_left: Point

    def __init__(self, width: float, height: float, color: Color, top_left: Point):
        super().__init__("Rectangle", color)
        self.width = width
        self.height = height
        self.top_left = top_left

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Drawing {self.name} at ({self.top_left.x}, {self.top_left.y})"

class Circle(ShapeBase, IDrawable):
    radius: float
    center: Point

    def __init__(self, radius: float, color: Color, center: Point):
        super().__init__("Circle", color)
        self.radius = radius
        self.center = center

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def draw(self) -> str:
        return f"Drawing {self.name} with radius {self.radius}"

