# Utils module - helper functions and classes
from types import Color, Point
from shapes import IShape, Rectangle, Circle

def format_shape_info(shape: IShape) -> str:
    return f"Area: {shape.area():.2f}, Perimeter: {shape.perimeter():.2f}"

def create_default_point() -> Point:
    return Point(0.0, 0.0)

class ShapeFactory:
    shapes_created: int

    def __init__(self):
        self.shapes_created = 0

    def create_red_rectangle(self, w: float, h: float) -> Rectangle:
        self.shapes_created = self.shapes_created + 1
        origin: Point = create_default_point()
        return Rectangle(w, h, Color.RED, origin)

    def create_blue_circle(self, r: float) -> Circle:
        self.shapes_created = self.shapes_created + 1
        center: Point = Point(5.0, 5.0)
        return Circle(r, Color.BLUE, center)

    def get_count(self) -> int:
        return self.shapes_created
